var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"이면세계 가변 심도 좌표\\n<color=#ff3636>필하모닉 홀</color>","JPN":"裏世界可変深度座標\\n<color=#ff3636>フィルハーモニーホール</color>","ENG":"Counterside Variable Depth Coordinates\\n<color=#ff3636>Philharmonic Hall</color>","TWN":"異界可變深度座標\\n<color=#ff3636>管弦樂廳</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제9 포격전대 <color=#ffd34c>메이즈</color>\\n추가 배치 완료","JPN":"管理局第9砲撃戦隊<color=#ffd34c>メイズ</color>\\n追加配置完了","ENG":"Administration 9th Artillery Division <color=#ffd34c>Maze</color>\\nAdditional deployment complete","TWN":"管理局第9炮擊戰隊<color=#ffd34c>梅茲</color>\\n追加部署已完成"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전대원! 신속하게 강하 지점을 확보하도록!","JPN":"全隊員！　迅速に降下地点を確保するように！","ENG":"All units! Swiftly secure the drop zone!","TWN":"全體成員！快速確保降落區域安全！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전선의 후방부터 차례로 기갑병력을 배치. 장거리 화력투사로 적을 섬멸한다!","JPN":"前線の後方より順次機甲兵力を配置。遠距離からの火力投射により敵を殲滅する！","ENG":"Place the armored units starting from the back. We will eliminate the enemy with long-ranged firepower!","TWN":"從前線後方依次部署裝甲部隊。用遠距離火力投射殲滅敵人！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"메이즈 전대장님! 도착하셨군요!","JPN":"メイズ戦隊長！　来てくださいましたか！","ENG":"Maze Commander! You're here!","TWN":"梅茲戰隊長！你來了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"모네카! 연합 전대는 어떻게 됐지?","JPN":"モネカ！　連合戦隊の様子は？","ENG":"Moneka! How are the coalition divisions?","TWN":"莫奈卡！聯合戰隊怎麼樣了？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"연합 전대는 커튼콜 강습 작전으로 상당수의 최고단원은 처리하는데 성공했습니다.","JPN":"カーテンコール強襲作戦により、連合戦隊は大半の主席奏者を撃破しました。","ENG":"The coalition divisions have successfully eliminated many Elite Members in the Curtain Call Operation.","TWN":"聯合戰隊透過強襲作戰成功消滅了大部分的樂手。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"하지만 예상보다 빨리 마에스트로가 필하모닉 홀에 복귀하여 전선이 흐트러졌습니다.","JPN":"しかし予想より早くマエストロがフィルハーモニーホールに帰還したため、戦線が乱れています。","ENG":"But Maestra's return to Philharmonic Hall was earlier than expected, causing our forefront to scatter.","TWN":"但指揮家比預期更早返回管弦樂廳，導致前線陷入混亂。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이에 따라, 최전선에 있는 인원과는 현재 통신이 불가능합니다.","JPN":"そのため、最前線とは現在通信が途切れた状態です。","ENG":"Accordingly, communication is currently impossible with personnel on the forefront.","TWN":"因此，目前無法與前線人員通訊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알겠다. 곧 다른 전대들도 순차적으로 도착할 것이다.","JPN":"わかった。すぐに他の戦隊も着く予定だ。","ENG":"Understood. The other divisions will follow suit in due course.","TWN":"我知道了。其他戰隊很快也將陸續抵達。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전장의 전우들에게 조금만 더 버텨달라고 전하도록.","JPN":"戦場の戦友たちには、あと少しだけ踏ん張るように伝えてくれ。","ENG":"Send word to our comrades on the battlefield to hold on for a little longer.","TWN":"告訴戰場上的戰友再堅持一會下。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"마지막으로 자네는 어떻지, 앨리스?","JPN":"君はどうだ、アリス？","ENG":"Lastly, how are you doing, Alice?","TWN":"最後，你打算怎麼辦，艾莉絲？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"장비의 조정은 마쳤나?","JPN":"装備の調整は済んだか？","ENG":"Have you finished adjusting your gear?","TWN":"裝備調整完畢了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"문제없습니다, 메이즈 전대장님.","JPN":"問題ありません、メイズ戦隊長。","ENG":"No problems here, Maze Commander.","TWN":"沒問題，梅茲戰隊長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_05"},{"id":"L23_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제4 수색전대 <color=#ffd34c>야크샤</color>\\n전대원 앨리스","JPN":"管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>\\n戦隊員アリス","ENG":"Administration 4th Recon Division <color=#ffd34c>Yaksha</color>\\nAlice","TWN":"管理局第4偵察戰隊<color=#ffd34c>夜叉</color>\\n戰隊員艾莉絲"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"맡겨주십시오. 언제든 출격할 수 있습니다.","JPN":"任せてください。いつでも出撃できます。","ENG":"Just tell me when. I'm ready to deploy at any time.","TWN":"交給我把。隨時可以出擊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히익!! 문제가 없긴 뭐가 없습니까요! 이 하룻고양이!","JPN":"キヒイ！！　問題大ありでやんす！　このヘタクソ猫！","ENG":"Eep!! What do you mean, \\"No problem,\\" you foolish cat!","TWN":"吱！！什麼沒有問題！你這隻笨貓！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"비스트 클로는 원래 라이오넬 전대장님을 위해 만들어진 고유무장입니다요!","JPN":"ビーストクローは元々ライオネル戦隊長のために作られた固有武装！","ENG":"Beast Claw is Unique Gear that was originally made for Commander Lionel!","TWN":"魔獸爪是最初為萊諾戰隊長打造的專屬裝備！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"최대한 조정해봤지만, 리스크는 그대로고 출력은 원래의 반 정도밖에 안 나올 겁니다요!","JPN":"最大限調整してもリスクは変わらないし、出力は本来の半分しか出ないでやんす！","ENG":"No matter how much you adjust it, the risks are the same and the output is one fourth of the original!","TWN":"我盡可能調整過了，但是風險還是一樣，輸出卻只有原來的一半！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"맞지도 않는 신발을 신고 전력질주를 하는 거랑 똑같단 말입니다요!","JPN":"サイズの合わない靴を履いて全力疾走するのと同じでやんす！","ENG":"This is the same as sprinting with shoes that don't fit!","TWN":"就像、就像穿著不合腳的鞋子短跑一樣！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"괜찮아. 달릴 수만 있다면, 누구보다 빨리 도착해 줄 테니까.","JPN":"構わない。走ることさえ出来れば、誰よりも速くゴールしてやるから。","ENG":"It's okay. If I can sprint, I'll arrive faster than anyone.","TWN":"沒關係。只要能比其他人早一步到那裡就行。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"으으……! 아주 말을 안 듣습니다요! 고집불통입니다요!","JPN":"うう……！　本当に言うこと聞かないでやんす！　強情でやんす！","ENG":"Ngh...! You're not listening to me! So stubborn!","TWN":"呃……！你根本沒在聽！一根筋！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"대신 출력의 부족분만큼 카운터 능력과 시너지를 낼 수 있는 슈트를 준비했습니다요.","JPN":"代わりに、足りない出力を補えるようにカウンター能力を向上させてくれるスーツを用意したでやんす。","ENG":"Instead, I've prepared a suit that will synergize with your Counter ability to compensate for the shortage in output.","TWN":"還有，我準備了一套發揮出與制裁者能力相同的強化服，來彌補輸出的不足。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 슈트가 있으면 조금 더 수월하게 속도를 낼 수 있을 겁니다요.","JPN":"そのスーツがあれば、もう少しスピードを出せるはずでやんす。","ENG":"If you wear this suit, you'll be able to speed up more easily.","TWN":"穿上這套衣服就能更輕易地進行加速。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그게 이 슈트란 말이지? 쪼끄만게 보기보다 제법이잖아?","JPN":"そうなんだ。見かけによらずやるじゃん。","ENG":"This is the suit? Why aren't you a clever short stack!","TWN":"你說這套武裝？小鬼你不錯嘛？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"아무튼 고맙다, 꼬맹아. 안아줄까?","JPN":"ありがとう、チビ。ハグでもしてやろうか？","ENG":"Anyway, thanks, kid. Wanna hug?","TWN":"不管怎樣，謝謝你，小鬼。要來抱一下嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"우갸아악……! 땀냄새 나니까 떨어지는 겁니다요……!","JPN":"うぎゃああ……！　汗臭いから離れろでやんす……！","ENG":"Uwaaagh...!! Get away from me! You smell like sweat...!","TWN":"嗚哇啊啊……！我是被你的汗味臭到哭的……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 명심하도록. 앨리스.","JPN":"ゴホン、肝に銘じておけ、アリス。","ENG":"Ahem. Alice, don't forget.","TWN":"咳，記住這一點。艾莉絲。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"어디까지나 자네는 현재 메이즈의 임시 전력으로 이곳에 있는 것이다.","JPN":"あくまで君は今、メイズの臨時戦力としてここにいる。","ENG":"You're currently here as Maze's backup.","TWN":"無論如何，你現在是作為梅茲的臨時增援存在的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"급한 마음은 알겠지만, 전장에서는 내 지시를 우선시해주었으면 좋겠군.","JPN":"焦る気持ちはわかるが、戦場では私の指示を優先してくれ。","ENG":"I know you're anxious, but I hope you will prioritize my orders on the battlefield.","TWN":"我知道你很著急，但我希望你在戰場上優先聽從我的指示。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"네, 명심하겠습니다. 전대장님.","JPN":"はい、心に留めておきます。戦隊長。","ENG":"Understood, Commander.","TWN":"是的，我會記住這一點。戰隊長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"포격전대 메이즈는 초장거리 화력 투사를 통해 적을 섬멸하는 것이 기본 전략.","JPN":"砲撃戦隊メイズは、超遠距離からの火力投射による殲滅戦を得意としている。","ENG":"Artillery Division Maze's basic strategy is to annihilate our enemies using ultra-long-range firepower.","TWN":"梅茲炮擊戰隊的基本策略，是透過超遠距離火力投射殲滅敵人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 아직 우리 전대는 근접 전력이 부족해.","JPN":"しかし、その分まだ近接戦の戦略には隙がある。","ENG":"But my division lacks close-range combatants.","TWN":"但我們戰隊還缺乏近戰兵力。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이 작전에서는 자네가 그 공백을 메워주길 바라네.","JPN":"今回の作戦では、その隙を君に埋めてほしいと思っている。","ENG":"I hope you can fill that hole for this operation.","TWN":"在這次作戰中，我們希望你能填補這個空缺。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전이 시작되면 자네는 지정된 포인트를 확보 후. 대기.","JPN":"作戦開始後、君は指定ポイントを確保した後、待機しろ。","ENG":"Once the operation starts, you will secure the designated point, then wait for further orders.","TWN":"作戰開始後，我們需要你確保指定位置的安全，隨後等待下一步命令。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"기갑 전력의 화력이 확보되면, 자네에게 길을 열어주도록 하지.","JPN":"機甲戦力の火力が確保されたら、君が進む道を開けよう。","ENG":"Once our armored units secure their firepower, we'll open the way for you.","TWN":"一旦我們的裝甲部隊部署完畢，我們就會為你開出一條路。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};